#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        static char S[300005]; scanf("%s", S);
        long long best = 0;
        for(int start=0; start<=1; ++start){
            int prev = start; // X1
            int cnt = 0;
            // we will keep a sliding window of last two bits
            int w1 = -1, w2 = -1; // not used for first two positions
            for(int i=0;i<N;i++){
                int cur;
                if(i==0) cur = prev;
                else cur = prev ^ (S[i-1]-'0');
                // shift window
                if(i>=2){
                    if(w1==1 && w2==1 && cur==1) cnt++;
                }
                w1 = w2;
                w2 = cur;
                prev = cur;
            }
            if(cnt>best) best = cnt;
        }
        printf("%lld\n", best);
    }
    return 0;
}

